import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Link } from 'react-router-dom';
import { getVisits, updateVisitStatus, getLeases, getAdminProperties, getOwnerProperties, deleteProperty, toggleProperty, getVisitsByOwner, getVisitsByTenant, updateLeaseStatus, requestVisitReschedule, decideVisitReschedule, tenantUpdateVisitStatus, getVisitMessages, postVisitMessage, getLeaseMessages, postLeaseMessage } from '../api';

export default function Dashboard() {
  const [activeTab, setActiveTab] = useState('overview');
  const [visits, setVisits] = useState([]);
  const [leases, setLeases] = useState([]);
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');
  const [loaded, setLoaded] = useState({ overview: false, visits: false, leases: false, properties: false });
  const [toast, setToast] = useState({ visible: false, type: '', message: '' });
  const [rescheduleOpen, setRescheduleOpen] = useState(false);
  const [rescheduleVisit, setRescheduleVisit] = useState(null);
  const [rescheduleInput, setRescheduleInput] = useState('');
  const [rescheduleSubmitting, setRescheduleSubmitting] = useState(false);
  const [chatOpen, setChatOpen] = useState(false);
  const [chatTarget, setChatTarget] = useState(null);
  const [chatMessages, setChatMessages] = useState([]);
  const [chatInput, setChatInput] = useState('');
  const [chatSubmitting, setChatSubmitting] = useState(false);
  const [chatType, setChatType] = useState('visit'); // 'visit' or 'lease'
  const loadingRef = useRef(false);
  const abortRef = useRef(null);

  const storedUser = localStorage.getItem('user');
  const user = storedUser ? JSON.parse(storedUser) : null;

  function showToast(type, message) {
    setToast({ visible: true, type, message });
    // auto-hide after 3 seconds
    setTimeout(() => setToast({ visible: false, type, message }), 3000);
  }

  async function handleLeaseDecision(lease, status) {
    try {
      const updated = await updateLeaseStatus(lease.id, status);
      setLeases(prev => prev.map(l => l.id === lease.id ? { ...l, status: updated.status } : l));
      showToast('success', `Lease ${status.toLowerCase()}`);
    } catch (err) {
      console.error('Failed to update lease status:', err);
      showToast('error', 'Failed to update lease: ' + (err?.message || 'Unknown error'));
    }
  }

  function openOwnerRescheduleForm(visit) {
    const base = visit.visitDateTime ? new Date(visit.visitDateTime) : new Date();
    const pad = (n) => `${n}`.padStart(2, '0');
    const isoLocal = `${base.getFullYear()}-${pad(base.getMonth()+1)}-${pad(base.getDate())}T${pad(base.getHours())}:${pad(base.getMinutes())}`;
    setRescheduleInput(isoLocal);
    setRescheduleVisit(visit);
    setRescheduleOpen(true);
  }

  async function submitOwnerReschedule(e) {
    e?.preventDefault?.();
    if (!rescheduleVisit || !rescheduleInput) return;
    setRescheduleSubmitting(true);
    try {
      const updated = await requestVisitReschedule(rescheduleVisit.id, rescheduleInput);
      setVisits(prev => prev.map(v => v.id === rescheduleVisit.id ? { ...v, proposedDateTime: updated.proposedDateTime, rescheduleStatus: updated.rescheduleStatus } : v));
      setRescheduleOpen(false);
      setRescheduleVisit(null);
      setRescheduleInput('');
      showToast('success', 'Reschedule request sent');
    } catch (err) {
      console.error('Failed to request reschedule:', err);
      showToast('error', 'Failed to request reschedule: ' + (err?.message || 'Unknown error'));
    } finally {
      setRescheduleSubmitting(false);
    }
  }

  async function handleTenantRescheduleDecision(visit, decision) {
    try {
      const updated = await decideVisitReschedule(visit.id, decision);
      setVisits(prev => prev.map(v => v.id === visit.id ? { ...v, visitDateTime: updated.visitDateTime, proposedDateTime: updated.proposedDateTime, rescheduleStatus: updated.rescheduleStatus } : v));
      showToast('success', decision === 'ACCEPTED' ? 'Reschedule accepted' : 'Reschedule declined');
    } catch (err) {
      console.error('Failed to decide reschedule:', err);
      showToast('error', 'Failed to respond to reschedule: ' + (err?.message || 'Unknown error'));
    }
  }

  async function handleTenantToggleVisitStatus(visit) {
    const next = visit.status === 'PENDING' ? 'DONE' : 'PENDING';
    try {
      const updated = await tenantUpdateVisitStatus(visit.id, next);
      setVisits(prev => prev.map(v => v.id === visit.id ? { ...v, status: updated.status } : v));
      showToast('success', `Visit marked as ${next}`);
    } catch (err) {
      console.error('Failed to update visit status:', err);
      showToast('error', 'Failed to update visit: ' + (err?.message || 'Unknown error'));
    }
  }

  async function handleToggleAvailability(property) {
    try {
      const updated = await toggleProperty(property.id);
      // Optimistically update current list for snappier UI
      setProperties(prev => prev.map(p => p.id === property.id ? { ...p, available: updated?.available ?? !p.available } : p));
      // Refresh properties list
      const propertiesData = await getUserProperties();
      setProperties(propertiesData);
      const newStatus = updated?.available ?? !property.available;
      showToast('success', `Property marked as ${newStatus ? 'Available' : 'Occupied'}`);
    } catch (err) {
      console.error('Failed to toggle availability:', err);
      showToast('error', 'Failed to toggle availability: ' + (err?.message || 'Unknown error'));
    }
  }

  // helper: fetch properties owned by signed-in user
  async function getUserProperties() {
    if (!user?.id) return [];
    return await getOwnerProperties(user.id).catch(() => []);
  }

  const loadTabData = useCallback(async (tab) => {
    if (loadingRef.current) return; // prevent overlapping loads
    // If already loaded once, do not re-fetch automatically
    if (loaded[tab]) {
      setLoading(false);
      return;
    }
    setLoading(true);
    setErrorMsg('');
    // abort previous if any
    if (abortRef.current) {
      try { abortRef.current.abort(); } catch {}
    }
    const controller = new AbortController();
    abortRef.current = controller;
    try {
      if (tab === 'visits') {
        // Get visits where user is either owner or tenant
        const ownerVisits = await getVisitsByOwner(user.id).catch(() => []);
        const tenantVisits = await getVisitsByTenant(user.email).catch(() => []);
        // Combine and deduplicate visits
        const allVisits = [...ownerVisits, ...tenantVisits].filter((visit, index, self) => 
          index === self.findIndex(v => v.id === visit.id)
        );
        setVisits(allVisits || []);
        setLoaded(prev => ({ ...prev, visits: true }));
      } else if (tab === 'leases') {
        const leasesData = await getLeases().catch(() => []);
        setLeases(leasesData || []);
        setLoaded(prev => ({ ...prev, leases: true }));
      } else if (tab === 'properties') {
        // Load properties owned by user
        const propertiesData = await getUserProperties();
        setProperties(propertiesData || []);
        setLoaded(prev => ({ ...prev, properties: true }));
      } else if (tab === 'overview') {
        // Load all data for overview
        const ownerVisits = await getVisitsByOwner(user.id).catch(() => []);
        const tenantVisits = await getVisitsByTenant(user.email).catch(() => []);
        const allVisits = [...ownerVisits, ...tenantVisits].filter((visit, index, self) => 
          index === self.findIndex(v => v.id === visit.id)
        );
        setVisits(allVisits || []);

        const l = await getLeases().catch(() => []);
        setLeases(l || []);

        const propertiesData = await getUserProperties();
        setProperties(propertiesData || []);
        setLoaded(prev => ({ ...prev, overview: true }));
      }
    } catch (err) {
      console.error('Error loading tab data:', err);
      setErrorMsg(err?.message || 'Failed to load data');
    } finally {
      setLoading(false);
      loadingRef.current = false;
      setLoaded(prev => ({ ...prev, [tab]: true }));
    }
  }, [user?.id, user?.email]);

  useEffect(() => {
    if (!user) return;
    loadTabData(activeTab);
    return () => {
      if (abortRef.current) {
        try { abortRef.current.abort(); } catch {}
      }
    };
  }, [activeTab, loadTabData, user]);

  async function handleDeleteProperty(id) {
    if (!window.confirm('Are you sure you want to delete this property? This action cannot be undone.')) return;
    try {
      // Optimistically update UI first
      setProperties(prev => prev.filter(p => p.id !== id));
      await deleteProperty(id);
      // Refresh properties list
      const propertiesData = await getUserProperties().catch(() => []);
      setProperties(propertiesData || []);
      showToast('success', 'Property deleted successfully');
    } catch (err) {
      console.error('Failed to delete property:', err);
      showToast('error', 'Failed to delete property: ' + (err?.message || 'Unknown error'));
    }
  }

  // Chat functions
  async function openVisitChat(visit) {
    setChatTarget(visit);
    setChatType('visit');
    setChatOpen(true);
    setChatMessages([]);
    setChatInput('');
    try {
      const messages = await getVisitMessages(visit.id);
      setChatMessages(messages || []);
    } catch (err) {
      console.error('Failed to load visit messages:', err);
    }
  }

  async function openLeaseChat(lease) {
    setChatTarget(lease);
    setChatType('lease');
    setChatOpen(true);
    setChatMessages([]);
    setChatInput('');
    try {
      const messages = await getLeaseMessages(lease.id);
      setChatMessages(messages || []);
    } catch (err) {
      console.error('Failed to load lease messages:', err);
    }
  }

  async function sendChatMessage(e) {
    e.preventDefault();
    if (!chatInput.trim() || chatSubmitting) return;
    setChatSubmitting(true);
    try {
      const newMessage = chatType === 'visit' 
        ? await postVisitMessage(chatTarget.id, chatInput)
        : await postLeaseMessage(chatTarget.id, chatInput);
      setChatMessages(prev => [...prev, newMessage]);
      setChatInput('');
    } catch (err) {
      console.error('Failed to send message:', err);
      showToast('error', 'Failed to send message');
    } finally {
      setChatSubmitting(false);
    }
  }

  if (!user) {
    return (
      <div className="text-center" style={{ padding: '4rem' }}>
        <h2>Please log in to view your dashboard</h2>
        <Link to="/login" className="btn">Login</Link>
      </div>
    );
  }

  return (
    <div className="dashboard-container">
      {toast.visible && (
        <div style={{
          position: 'fixed',
          top: '20px',
          right: '20px',
          padding: '1rem 1.5rem',
          borderRadius: '0.5rem',
          color: 'white',
          fontWeight: '600',
          zIndex: 1000,
          background: toast.type === 'success' ? '#10b981' : toast.type === 'error' ? '#ef4444' : '#3b82f6',
          boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1), 0 4px 6px -4px rgba(0,0,0,0.1)'
        }}
          role="alert"
        >
          {toast.message}
        </div>
      )}

      {/* Owner Reschedule Modal */}
      {rescheduleOpen && (
        <div className="modal-overlay" onClick={() => setRescheduleOpen(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
              <h3>Request Visit Reschedule</h3>
              <button type="button" onClick={() => setRescheduleOpen(false)} style={{ background: 'none', border: 'none', fontSize: '1.5rem', cursor: 'pointer' }}>×</button>
            </div>

            <form onSubmit={submitOwnerReschedule}>
              <div className="form-group">
                <label className="form-label">New Date & Time</label>
                <input
                  type="datetime-local"
                  value={rescheduleInput}
                  onChange={(e) => setRescheduleInput(e.target.value)}
                  min={new Date().toISOString().slice(0,16)}
                  required
                />
              </div>
              <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end' }}>
                <button type="button" className="btn-secondary" onClick={() => setRescheduleOpen(false)}>Cancel</button>
                <button type="submit" disabled={rescheduleSubmitting}>{rescheduleSubmitting ? 'Submitting…' : 'Submit'}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Chat Modal */}
      {chatOpen && chatTarget && (
        <div className="modal-overlay" onClick={() => setChatOpen(false)}>
          <div className="modal-content chat-modal" onClick={(e) => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
              <h3>Chat - {chatType === 'visit' ? `Visit #${chatTarget.id}` : `Lease #${chatTarget.id}`}</h3>
              <button type="button" onClick={() => setChatOpen(false)} style={{ background: 'none', border: 'none', fontSize: '1.5rem', cursor: 'pointer' }}>×</button>
            </div>

            <div className="chat-messages" style={{ height: '300px', overflowY: 'auto', border: '1px solid #e5e7eb', borderRadius: '0.375rem', padding: '1rem', marginBottom: '1rem' }}>
              {chatMessages.length === 0 ? (
                <p style={{ color: '#6b7280', textAlign: 'center' }}>No messages yet. Start the conversation!</p>
              ) : (
                chatMessages.map(msg => (
                  <div key={msg.id} style={{ marginBottom: '0.75rem' }}>
                    <div style={{ fontSize: '0.75rem', color: '#6b7280', marginBottom: '0.25rem' }}>
                      {msg.senderEmail} • {new Date(msg.createdAt).toLocaleString()}
                    </div>
                    <div style={{ 
                      background: msg.senderEmail === user.email ? '#667eea' : '#f3f4f6', 
                      color: msg.senderEmail === user.email ? 'white' : '#1f2937',
                      padding: '0.5rem 0.75rem',
                      borderRadius: '0.5rem',
                      maxWidth: '80%'
                    }}>
                      {msg.content}
                    </div>
                  </div>
                ))
              )}
            </div>

            <form onSubmit={sendChatMessage} style={{ display: 'flex', gap: '0.5rem' }}>
              <input
                type="text"
                value={chatInput}
                onChange={(e) => setChatInput(e.target.value)}
                placeholder="Type your message..."
                style={{ flex: 1, padding: '0.5rem', border: '1px solid #d1d5db', borderRadius: '0.375rem' }}
                required
              />
              <button type="submit" disabled={chatSubmitting} className="btn">
                {chatSubmitting ? 'Sending…' : 'Send'}
              </button>
            </form>
          </div>
        </div>
      )}

      <div className="dashboard-grid">
        {/* Sidebar */}
        <div className="sidebar">
          <div style={{ marginBottom: '2rem' }}>
            <div style={{ 
              width: '60px', 
              height: '60px', 
              borderRadius: '50%', 
              background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: 'white',
              fontWeight: '700',
              fontSize: '1.5rem',
              margin: '0 auto 1rem'
            }}>
              {user.name?.charAt(0)?.toUpperCase()}
            </div>
            <div style={{ textAlign: 'center' }}>
              <h3 style={{ textAlign: 'center', marginBottom: '0.5rem' }}>{user.name}</h3>
              <p style={{ textAlign: 'center', color: '#6b7280', fontSize: '0.875rem' }}>
                {user.email}
              </p>
            </div>
          </div>

          <nav>
            <button
              onClick={() => setActiveTab('overview')}
              className={activeTab === 'overview' ? 'active' : ''}
              style={{ 
                width: '100%', 
                textAlign: 'left', 
                background: 'none', 
                border: 'none',
                padding: '0.75rem 1rem',
                borderRadius: '0.5rem',
                cursor: 'pointer',
                transition: 'all 0.3s ease',
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                color: '#4a5568',
                fontWeight: 600
              }}
            >
              <span role="img" aria-label="overview">📊</span>
              <span>Overview</span>
            </button>
            <button
              onClick={() => setActiveTab('visits')}
              className={activeTab === 'visits' ? 'active' : ''}
              style={{ 
                width: '100%', 
                textAlign: 'left', 
                background: 'none', 
                border: 'none',
                padding: '0.75rem 1rem',
                borderRadius: '0.5rem',
                cursor: 'pointer',
                transition: 'all 0.3s ease',
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                color: '#4a5568',
                fontWeight: 600
              }}
            >
              <span role="img" aria-label="visits">📅</span>
              <span>My Visits</span>
            </button>
            <button
              onClick={() => setActiveTab('leases')}
              className={activeTab === 'leases' ? 'active' : ''}
              style={{ 
                width: '100%', 
                textAlign: 'left', 
                background: 'none', 
                border: 'none',
                padding: '0.75rem 1rem',
                borderRadius: '0.5rem',
                cursor: 'pointer',
                transition: 'all 0.3s ease',
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                color: '#4a5568',
                fontWeight: 600
              }}
            >
              <span role="img" aria-label="leases">📋</span>
              <span>My Leases</span>
            </button>
            <button
              onClick={() => setActiveTab('properties')}
              className={activeTab === 'properties' ? 'active' : ''}
              style={{
                width: '100%',
                textAlign: 'left',
                background: 'none',
                border: 'none',
                padding: '0.75rem 1rem',
                borderRadius: '0.5rem',
                cursor: 'pointer',
                transition: 'all 0.3s ease',
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                color: '#4a5568',
                fontWeight: 600
              }}
            >
              <span role="img" aria-label="properties">🏠</span>
              <span>My Properties</span>
            </button>
          </nav>
        </div>

        {/* Main Content */}
        <div className="main-content">
          {loading ? (
            <div className="text-center" style={{ padding: '4rem' }}>
              <div className="loading" style={{ width: '40px', height: '40px', margin: '0 auto' }}></div>
              <p style={{ marginTop: '1rem', color: '#6b7280' }}>Loading dashboard...</p>
              {errorMsg && (
                <p style={{ marginTop: '0.5rem', color: '#ef4444' }}>{errorMsg}</p>
              )}
            </div>
          ) : (
            <>
              {errorMsg && (
                <div style={{
                  background: '#fee2e2', color: '#991b1b', padding: '0.75rem', borderRadius: '0.5rem', marginBottom: '1rem', border: '1px solid #fecaca'
                }}>
                  {errorMsg}
                </div>
              )}
              {activeTab === 'overview' && (
                <div>
                  <h2 style={{ marginBottom: '2rem' }}>Dashboard Overview</h2>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div style={{ background: 'white', padding: '2rem', borderRadius: '1rem', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}>
                      <h3 style={{ fontSize: '2rem', fontWeight: '800', color: '#667eea' }}>{visits.length}</h3>
                      <p style={{ color: '#6b7280' }}>Scheduled Visits</p>
                    </div>
                    <div style={{ background: 'white', padding: '2rem', borderRadius: '1rem', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}>
                      <h3 style={{ fontSize: '2rem', fontWeight: '800', color: '#10b981' }}>{leases.length}</h3>
                      <p style={{ color: '#6b7280' }}>Active Leases</p>
                    </div>
                    <div style={{ background: 'white', padding: '2rem', borderRadius: '1rem', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}>
                        <h3 style={{ fontSize: '2rem', fontWeight: '800', color: '#f59e0b' }}>{properties.length}</h3>
                        <p style={{ color: '#6b7280' }}>My Properties</p>
                      </div>
                  </div>
                </div>
              )}

              {activeTab === 'visits' && (
                <div>
                  <h2 style={{ marginBottom: '2rem' }}>My Visits</h2>
                  {visits.length === 0 ? (
                    <div className="text-center" style={{ padding: '3rem' }}>
                      <p style={{ color: '#6b7280', marginBottom: '1rem' }}>No visits scheduled yet.</p>
                      <Link to="/" className="btn">Browse Properties</Link>
                    </div>
                  ) : (
                    <div className="table-container" style={{ overflowX: 'auto' }}>
                      <table>
                        <thead>
                          <tr>
                            <th>Property</th>
                            <th>Date</th>
                            <th>Status</th>
                            <th>Actions</th>
                          </tr>
                        </thead>
                        <tbody>
                          {visits.map(visit => (
                            <tr key={visit.id}>
                              <td>
                                <Link to={`/property/${visit.propertyId}`} style={{ textDecoration: 'none', color: '#667eea' }}>
                                  {visit.propertyTitle || `Property #${visit.propertyId}`}
                                </Link>
                              </td>
                              <td>{visit.visitDateTime ? new Date(visit.visitDateTime).toLocaleString() : 'N/A'}</td>
                              <td>
                                <span style={{
                                  padding: '0.25rem 0.75rem',
                                  borderRadius: '9999px',
                                  fontSize: '0.75rem',
                                  fontWeight: '600',
                                  background: visit.status === 'DONE' ? '#10b981' : visit.status === 'PENDING' ? '#f59e0b' : '#ef4444',
                                  color: 'white'
                                }}>
                                  {visit.status}
                                </span>
                              </td>
                              <td>
                                <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                                  <button className="btn" onClick={() => openVisitChat(visit)}>
                                    💬 Chat
                                  </button>
                                  {visit.rescheduleStatus === 'PENDING' && visit.proposedDateTime && (
                                    <div style={{ display: 'flex', gap: '0.25rem' }}>
                                      <button className="btn-success" onClick={() => handleTenantRescheduleDecision(visit, 'ACCEPTED')}>✓</button>
                                      <button className="btn-danger" onClick={() => handleTenantRescheduleDecision(visit, 'DECLINED')}>✗</button>
                                    </div>
                                  )}
                                  <button className="btn-secondary" onClick={() => handleTenantToggleVisitStatus(visit)}>
                                    {visit.status === 'DONE' ? '↺ Mark Pending' : '✓ Mark Done'}
                                  </button>
                                </div>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'leases' && (
                <div>
                  <h2 style={{ marginBottom: '2rem' }}>My Leases</h2>
                  {leases.length === 0 ? (
                    <div className="text-center" style={{ padding: '3rem' }}>
                      <p style={{ color: '#6b7280', marginBottom: '1rem' }}>No lease applications yet.</p>
                      <Link to="/" className="btn">Browse Properties</Link>
                    </div>
                  ) : (
                    <div className="table-container" style={{ overflowX: 'auto' }}>
                      <table>
                        <thead>
                          <tr>
                            <th>Property</th>
                            <th>Tenant</th>
                            <th>Start Date</th>
                            <th>End Date</th>
                            <th>Status</th>
                            <th>Actions</th>
                          </tr>
                        </thead>
                        <tbody>
                          {leases.map(lease => (
                            <tr key={lease.id}>
                              <td>
                                <Link to={`/property/${lease.propertyId}`} style={{ textDecoration: 'none', color: '#667eea' }}>
                                  {lease.propertyTitle || `Property #${lease.propertyId}`}
                                </Link>
                              </td>
                              <td>{lease.tenantEmail}</td>
                              <td>{lease.startDate ? new Date(lease.startDate).toLocaleDateString() : 'N/A'}</td>
                              <td>{lease.endDate ? new Date(lease.endDate).toLocaleDateString() : 'N/A'}</td>
                              <td>
                                <span style={{
                                  padding: '0.25rem 0.75rem',
                                  borderRadius: '9999px',
                                  fontSize: '0.75rem',
                                  fontWeight: '600',
                                  background: lease.status === 'ACTIVE' ? '#10b981' : lease.status === 'APPROVED' ? '#3b82f6' : lease.status === 'DRAFT' ? '#6b7280' : lease.status === 'REJECTED' ? '#ef4444' : '#f59e0b',
                                  color: 'white'
                                }}>
                                  {lease.status}
                                </span>
                              </td>
                              <td>
                                <button className="btn" onClick={() => openLeaseChat(lease)}>
                                  💬 Chat
                                </button>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>
              )}

              {activeTab === 'properties' && (
                <div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                    <h2>My Properties</h2>
                    <Link to="/post" className="btn">+ Add Property</Link>
                  </div>
                  {properties.length === 0 ? (
                    <div className="text-center" style={{ padding: '3rem' }}>
                      <p style={{ color: '#6b7280', marginBottom: '1rem' }}>No properties listed yet.</p>
                      <Link to="/post" className="btn">List Your First Property</Link>
                    </div>
                  ) : (
                    <div className="property-grid" style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
                      gap: '1.25rem'
                    }}>
                      {properties.map((property) => (
                        <div key={property.id} className="property-card">
                          <Link to={`/property/${property.id}`} style={{ textDecoration: 'none', color: 'inherit' }}>
                            <h3 className="property-title truncate" style={{ fontSize: '1.1rem', fontWeight: '700', marginBottom: '0.35rem' }}>
                              {property.title}
                            </h3>
                            <p className="property-address truncate" style={{ color: '#6b7280', fontSize: '0.875rem', marginBottom: '0.5rem' }}>
                              {property.address}, {property.city}
                            </p>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.75rem' }}>
                              <span className="property-price" style={{ fontSize: '1.25rem', fontWeight: '700', color: '#10b981' }}>
                                ₹{property.price?.toLocaleString('en-IN') || 'N/A'}
                                <span style={{ fontSize: '0.75rem', color: '#6b7280', fontWeight: '400' }}>/month</span>
                              </span>
                              <span style={{
                                padding: '0.25rem 0.75rem',
                                borderRadius: '9999px',
                                fontSize: '0.75rem',
                                fontWeight: '600',
                                background: property.available ? '#10b981' : '#ef4444',
                                color: 'white'
                              }}>
                                {property.available ? 'Available' : 'Occupied'}
                              </span>
                            </div>
                          </Link>
                          <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.75rem' }}>
                            <button className="btn-secondary" onClick={() => window.location.href = `/property/${property.id}`}>
                              View
                            </button>
                            <button className="btn" onClick={() => handleToggleAvailability(property)}>
                              {property.available ? 'Mark Occupied' : 'Mark Available'}
                            </button>
                            <button className="btn-danger" onClick={() => handleDeleteProperty(property.id)}>
                              Delete
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}
